#include <stdio.h>

int main() {
 FILE *fp;
 char buffer[1024];

 fp = popen("ls -l", "r");
 if (!fp) {
 perror("popen failed");
 return 1;
 }

 while (fgets(buffer, sizeof(buffer), fp) != NULL) {
 printf("LS Output: %s", buffer);
 }

 int status = pclose(fp);
 return WEXITSTATUS(status);
}

#include <stdio.h>

int main() {
 FILE *fp = popen("grep 'important'", "w");
 if (!fp) {
 perror("popen failed");
 return 1;
 }

 fprintf(fp, "This is important\n");
 fprintf(fp, "This is not\n");
 fprintf(fp, "important message\n");

 pclose(fp);
 return 0;
}

#include <stdio.h>
#include <errno.h>
#include <sys/wait.h>

int main() {
 FILE *fp = popen("invalid_command", "r");
 if (!fp) {
 printf("popen error: %s\n", strerror(errno));
 return 1;
 }

 // ... processing would go here ...

 int status = pclose(fp);
 if (status == -1) {
 perror("pclose error");
 } else {
 printf("Command exited with status %d\n", WEXITSTATUS(status));
 }
 return 0;
}
